// Module: Uart_tx_fifo
// Description: 16x8-bit Synchronous FIFO buffer for UART TX module
//              Read-Through combinational output
//              Uses count-based empty/full detection
//============================================================================

module Uart_tx_fifo (
    input              clk,        // Clock (PCLK)
    input              rst_n,      // Async reset, active-low (PRESETn)
